async def send_post_request(url, data):
    ua = fake_useragent.UserAgent()
    user_agent = ua.random
    async with aiohttp.ClientSession(headers={"User-Agent": user_agent}) as session:
        response = await session.post(url, data=data)
        if response.status == 200:
            print(f"Жалоба отправлена от {data['phone']} {data['email']}!\n")
        else:
            print("Не удалось отправить жалобу\n")
async def send(text, amount):
    for _ in range(1, amount+1):
        email = random_email()
        number = random_number() 
        await send_post_request('https://telegram.org/support', {
            "message": text,
            "email": email,
            "phone": number
        })

async def launch_web(body): 
    tasks = []
    threads = int(input("\nКол-во потоков:"))
    amount = int(input("\nКол-во жалоб на один поток:"))
    for _ in range(threads): tasks.append(send(text=body,amount=amount))
    await asyncio.gather(*tasks)
